import { useEffect, useRef } from 'react';

const pageCss = ":root{\n    --bg:           #F8F9FA;\n    --bg-alt:       #FAFAF8;\n    --heading:      #2D3748;\n    --body:         #4A5568;\n    --muted:        #718096;\n    --accent-soft:  #8FBC8F;\n    --line:         #B38B6D;\n    --line-soft:    rgba(179, 139, 109, .28);\n    --line-faint:   rgba(45, 55, 72, .08);\n    --cta:          #576DB5;\n    --cta-hover:    #46599C;\n    --link:         #1E3A8A;\n    --font: 'Plus Jakarta Sans', system-ui, -apple-system, Segoe UI, sans-serif;\n    --max: 1320px;\n    --gutter: 24px;\n    --pad: clamp(20px, 4vw, 48px);\n  }\n\n  *{ box-sizing:border-box; }\n  html,body{ margin:0; padding:0; }\n  body{\n    background: var(--bg);\n    color: var(--body);\n    font-family: var(--font);\n    font-size: 16px; line-height: 1.6;\n    -webkit-font-smoothing: antialiased;\n    text-rendering: optimizeLegibility;\n    overflow-x: hidden;\n  }\n  a{ color: inherit; text-decoration: none; }\n  button{ font-family: inherit; cursor: pointer; border: 0; background: transparent; }\n\n  /* ============ NAV ============ */\n  .nav-wrap{\n    position:sticky; top:0; z-index:50;\n    backdrop-filter: blur(14px) saturate(140%);\n    -webkit-backdrop-filter: blur(14px) saturate(140%);\n    background: rgba(248, 249, 250, .72);\n    border-bottom: 1px solid var(--line-soft);\n  }\n  .container{\n    max-width: var(--max);\n    margin: 0 auto;\n    padding-left: var(--pad);\n    padding-right: var(--pad);\n    position: relative;\n  }\n  .nav{\n    display:grid; grid-template-columns: auto 1fr auto;\n    align-items:center; height:78px; gap:32px;\n  }\n  .logo{ display:flex; align-items:center; height:40px; }\n  .logo img{ height:38px; width:auto; display:block; }\n  .menu{ display:flex; justify-content:center; gap:6px; }\n  .menu a, .menu button.menu-link{\n    position:relative;\n    display:inline-flex; align-items:center; gap:6px;\n    padding:10px 14px;\n    font-size:14.5px; font-weight:500;\n    color:var(--body); border-radius:8px;\n    transition: color .2s ease, background .2s ease;\n  }\n  .menu a:hover, .menu button.menu-link:hover{ color:var(--heading); background: rgba(179,139,109,.06); }\n  .menu a::after{\n    content:\"\"; position:absolute; left:14px; right:14px; bottom:6px;\n    height:1px; background:var(--line); transform:scaleX(0); transform-origin:left;\n    transition: transform .25s ease;\n  }\n  .menu a:hover::after, .menu a.is-active::after{ transform:scaleX(1); }\n  .menu a.is-active, .menu button.menu-link.is-active{ color: var(--heading); }\n  .menu button.menu-link.is-active::after{\n    content:\"\"; position:absolute; left:14px; right:14px; bottom:6px;\n    height:1px; background:var(--line); transform:scaleX(1);\n  }\n  .menu .chev{ width:12px; height:12px; color:var(--muted); }\n\n  .nav-right{ display:flex; align-items:center; gap:8px; }\n  .lang{\n    display:inline-flex; align-items:center; gap:6px;\n    padding: 9px 12px;\n    font-size:13.5px; font-weight:600;\n    color:var(--body);\n    border:1px solid var(--line-soft);\n    border-radius: 999px;\n    background: rgba(255,255,255,.5);\n    transition: border-color .2s, color .2s, background .2s;\n  }\n  .lang:hover{ border-color:var(--line); color:var(--heading); background:#fff; }\n  .lang .globe{ color:var(--line); }\n  .lang .chev{ color:var(--muted); }\n  .icon-btn{\n    width:40px; height:40px;\n    display:grid; place-items:center;\n    border-radius:50%;\n    border:1px solid var(--line-soft);\n    color:var(--body);\n    background: rgba(255,255,255,.5);\n    transition: border-color .2s, color .2s, background .2s;\n  }\n  .icon-btn:hover{ border-color:var(--line); color:var(--heading); background:#fff; }\n\n  /* ============ BLOG HERO BANNER (3-col editorial magazine) ============ */\n  .bl-hero{\n    position: relative;\n    background: var(--bg);\n    padding: clamp(20px, 2.4vw, 32px) 0 clamp(56px, 7vw, 96px);\n    overflow: hidden;\n    border-bottom: 1px solid var(--line-faint);\n  }\n  .bl-hero::before{\n    content:\"\";\n    position: absolute; inset: 0;\n    background:\n      radial-gradient(900px 480px at 92% 8%, rgba(143,188,143,.10), transparent 65%),\n      radial-gradient(720px 480px at 8% 95%, rgba(179,139,109,.08), transparent 70%);\n    pointer-events: none;\n  }\n\n  /* Breadcrumb trail */\n  .bl-trail{\n    display: flex; align-items: center; gap: 8px;\n    padding-bottom: 14px;\n    margin-bottom: clamp(20px, 2.4vw, 32px);\n    border-bottom: 1px solid var(--line-faint);\n    font-size: 11.5px;\n    font-weight: 600;\n    color: var(--muted);\n  }\n  .bl-trail a{\n    color: var(--muted);\n    transition: color .2s;\n  }\n  .bl-trail a:hover{ color: var(--heading); }\n  .bl-trail svg{ color: var(--line); opacity: .7; }\n  .bl-trail .here{\n    color: var(--heading);\n    font-weight: 700;\n  }\n\n  /* Top masthead row */\n  .bl-mast{\n    display: grid;\n    grid-template-columns: repeat(12, 1fr);\n    gap: var(--gutter);\n    align-items: end;\n    margin-bottom: clamp(28px, 3vw, 40px);\n    padding-bottom: clamp(20px, 2.4vw, 32px);\n    border-bottom: 1px solid var(--line-faint);\n  }\n  .bl-mast-eyebrow{\n    grid-column: 1 / -1;\n    display: inline-flex; align-items: center; gap: 10px;\n    font-size: 11px; font-weight: 700;\n    letter-spacing: .26em; text-transform: uppercase;\n    color: var(--muted);\n    margin-bottom: 16px;\n  }\n  .bl-mast-eyebrow .swatch{ display: flex; gap: 3px; }\n  .bl-mast-eyebrow .swatch i{\n    display: block; width: 9px; height: 9px;\n    border-radius: 50%;\n  }\n  .bl-mast-eyebrow .swatch i:nth-child(1){ background: var(--accent-soft); }\n  .bl-mast-eyebrow .swatch i:nth-child(2){ background: var(--cta); }\n  .bl-mast-eyebrow .swatch i:nth-child(3){ background: var(--line); }\n\n  .bl-mast-h1{\n    grid-column: 1 / span 8;\n    font-size: clamp(40px, 5.4vw, 76px);\n    line-height: 1.0;\n    letter-spacing: -0.034em;\n    color: var(--heading);\n    font-weight: 700;\n    margin: 0;\n    text-wrap: balance;\n    max-width: 18ch;\n  }\n  .bl-mast-h1 .ital{\n    font-style: italic;\n    font-weight: 600;\n    color: var(--line);\n  }\n  .bl-mast-h1 .accent{\n    position: relative;\n    display: inline-block;\n    color: var(--heading);\n  }\n  .bl-mast-h1 .accent::before{\n    content:\"\";\n    position: absolute;\n    left: -2px; right: -2px;\n    bottom: 0.06em;\n    height: 14px;\n    background: linear-gradient(90deg, rgba(179,139,109,.32), rgba(143,188,143,.30));\n    border-radius: 3px;\n    z-index: -1;\n    transform: skewX(-6deg);\n  }\n  .bl-mast-lede{\n    grid-column: 9 / -1;\n    font-size: clamp(14.5px, 1.1vw, 16px);\n    line-height: 1.65;\n    color: var(--body);\n    margin: 0;\n    max-width: 38ch;\n    font-weight: 500;\n    padding-bottom: 10px;\n  }\n  .bl-mast-lede strong{ color: var(--heading); font-weight: 700; }\n\n  /* 3-COL EDITORIAL HERO LAYOUT */\n  .bl-edit-grid{\n    display: grid;\n    grid-template-columns: 0.85fr 1.5fr 0.85fr;\n    gap: clamp(20px, 2.4vw, 32px);\n    align-items: start;\n  }\n\n  /* === LEFT/RIGHT side: stacked compact cards === */\n  .bl-side{\n    display: flex; flex-direction: column;\n    gap: clamp(20px, 2.4vw, 28px);\n  }\n\n  .bl-side-card{\n    display: block;\n    text-decoration: none;\n    color: inherit;\n    transition: transform .35s cubic-bezier(.2,.7,.2,1);\n  }\n  .bl-side-card:hover{ transform: translateY(-4px); }\n\n  .bl-side-cover{\n    position: relative;\n    aspect-ratio: 4 / 3;\n    border-radius: 18px;\n    overflow: hidden;\n    border: 1px solid var(--line-soft);\n    transition: border-color .3s, box-shadow .3s;\n    isolation: isolate;\n  }\n  .bl-side-card:hover .bl-side-cover{\n    border-color: var(--line);\n    box-shadow: 0 24px 48px -28px rgba(179,139,109,.40);\n  }\n  .bl-side-cover::after{\n    content:\"\";\n    position: absolute; inset: 0;\n    background-image:\n      linear-gradient(rgba(45,55,72,.04) 1px, transparent 1px),\n      linear-gradient(90deg, rgba(45,55,72,.04) 1px, transparent 1px);\n    background-size: 24px 24px;\n    pointer-events: none;\n    opacity: .8;\n    z-index: 1;\n  }\n  .bl-side-cover svg{\n    position: absolute;\n    inset: 0; margin: auto;\n    width: 50%; height: 50%;\n    z-index: 2;\n    transition: transform .55s cubic-bezier(.2,.7,.2,1);\n  }\n  .bl-side-card:hover .bl-side-cover svg{ transform: scale(1.08); }\n\n  /* Per-card cover backdrops */\n  .bl-side-card.s1 .bl-side-cover{\n    background:\n      radial-gradient(280px 180px at 30% 30%, rgba(143,188,143,.30), transparent 60%),\n      radial-gradient(320px 220px at 75% 78%, rgba(87,109,181,.22), transparent 65%),\n      var(--bg-alt);\n  }\n  .bl-side-card.s2 .bl-side-cover{\n    background:\n      radial-gradient(280px 180px at 30% 30%, rgba(179,139,109,.28), transparent 60%),\n      radial-gradient(320px 220px at 75% 78%, rgba(143,188,143,.22), transparent 65%),\n      var(--bg-alt);\n  }\n  .bl-side-card.s3 .bl-side-cover{\n    background:\n      radial-gradient(280px 180px at 30% 30%, rgba(87,109,181,.26), transparent 60%),\n      radial-gradient(320px 220px at 75% 78%, rgba(179,139,109,.20), transparent 65%),\n      var(--bg-alt);\n  }\n  .bl-side-card.s4 .bl-side-cover{\n    background:\n      radial-gradient(280px 180px at 30% 30%, rgba(143,188,143,.28), transparent 60%),\n      radial-gradient(320px 220px at 75% 78%, rgba(179,139,109,.22), transparent 65%),\n      var(--bg-alt);\n  }\n\n  .bl-side-body{\n    padding-top: 14px;\n  }\n  .bl-side-cat{\n    display: inline-flex; align-items: center; gap: 6px;\n    font-size: 10.5px;\n    font-weight: 700;\n    letter-spacing: .22em;\n    text-transform: uppercase;\n    color: var(--cta);\n    margin-bottom: 8px;\n  }\n  .bl-side-cat::before{\n    content:\"\"; width: 5px; height: 5px;\n    border-radius: 50%;\n    background: currentColor;\n  }\n  .bl-side-card.s2 .bl-side-cat,\n  .bl-side-card.s3 .bl-side-cat{ color: var(--accent-soft); }\n  .bl-side-card.s4 .bl-side-cat{ color: var(--line); }\n\n  .bl-side-title{\n    font-size: 16px;\n    font-weight: 700;\n    line-height: 1.25;\n    letter-spacing: -0.018em;\n    color: var(--heading);\n    margin: 0 0 8px;\n    transition: color .25s;\n  }\n  .bl-side-card:hover .bl-side-title{ color: var(--cta); }\n  .bl-side-meta{\n    font-size: 11.5px;\n    font-weight: 600;\n    color: var(--muted);\n    letter-spacing: -0.005em;\n  }\n\n  /* === CENTER: featured hero post === */\n  .bl-feat{\n    display: block;\n    text-decoration: none;\n    color: inherit;\n    transition: transform .4s cubic-bezier(.2,.7,.2,1);\n  }\n  .bl-feat:hover{ transform: translateY(-4px); }\n\n  .bl-feat-cover{\n    position: relative;\n    aspect-ratio: 4 / 5;\n    border-radius: 22px;\n    overflow: hidden;\n    border: 1px solid var(--line-soft);\n    isolation: isolate;\n    transition: border-color .35s, box-shadow .35s;\n    background:\n      radial-gradient(420px 280px at 30% 30%, rgba(143,188,143,.32), transparent 60%),\n      radial-gradient(480px 320px at 75% 78%, rgba(87,109,181,.24), transparent 65%),\n      var(--bg-alt);\n  }\n  .bl-feat:hover .bl-feat-cover{\n    border-color: var(--line);\n    box-shadow: 0 40px 80px -40px rgba(179,139,109,.45);\n  }\n  .bl-feat-cover::after{\n    content:\"\";\n    position: absolute; inset: 0;\n    background-image:\n      linear-gradient(rgba(45,55,72,.04) 1px, transparent 1px),\n      linear-gradient(90deg, rgba(45,55,72,.04) 1px, transparent 1px);\n    background-size: 32px 32px;\n    pointer-events: none;\n    opacity: .8;\n    z-index: 1;\n  }\n  .bl-feat-cover svg{\n    position: absolute;\n    inset: 0; margin: auto;\n    width: 56%; height: 56%;\n    z-index: 2;\n    transition: transform .55s cubic-bezier(.2,.7,.2,1);\n  }\n  .bl-feat:hover .bl-feat-cover svg{ transform: scale(1.04); }\n\n  .bl-feat-badge{\n    position: absolute;\n    top: 22px; left: 22px;\n    z-index: 3;\n    display: inline-flex; align-items: center; gap: 8px;\n    padding: 8px 16px 8px 12px;\n    background: rgba(255,255,255,.92);\n    backdrop-filter: blur(10px);\n    -webkit-backdrop-filter: blur(10px);\n    border: 1px solid var(--line-soft);\n    border-radius: 999px;\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: .22em;\n    text-transform: uppercase;\n    color: var(--heading);\n  }\n  .bl-feat-badge::before{\n    content:\"\"; width: 6px; height: 6px;\n    border-radius: 50%;\n    background: var(--cta);\n    box-shadow: 0 0 0 4px rgba(87,109,181,.18);\n    animation: pulseDot 2.4s ease-in-out infinite;\n  }\n  @keyframes pulseDot{\n    0%,100%{ opacity: 1; transform: scale(1); }\n    50%{ opacity: .55; transform: scale(.85); }\n  }\n\n  .bl-feat-body{\n    padding: clamp(22px, 2.6vw, 32px) clamp(8px, 1.4vw, 18px) 0;\n    text-align: center;\n  }\n  .bl-feat-cat{\n    display: inline-flex; align-items: center; gap: 6px;\n    font-size: 11.5px;\n    font-weight: 700;\n    letter-spacing: .22em;\n    text-transform: uppercase;\n    color: var(--cta);\n    margin-bottom: 14px;\n  }\n  .bl-feat-cat::before{\n    content:\"\"; width: 5px; height: 5px;\n    border-radius: 50%;\n    background: var(--accent-soft);\n  }\n  .bl-feat-title{\n    font-size: clamp(26px, 3vw, 40px);\n    font-weight: 700;\n    line-height: 1.12;\n    letter-spacing: -0.022em;\n    color: var(--heading);\n    margin: 0 auto 16px;\n    max-width: 22ch;\n    transition: color .25s;\n    text-wrap: balance;\n  }\n  .bl-feat:hover .bl-feat-title{ color: var(--cta); }\n  .bl-feat-excerpt{\n    font-size: 14.5px;\n    line-height: 1.65;\n    color: var(--body);\n    margin: 0 auto 16px;\n    max-width: 56ch;\n    font-weight: 500;\n  }\n  .bl-feat-meta{\n    display: inline-flex; align-items: center; gap: 8px;\n    font-size: 12px;\n    color: var(--muted);\n    font-weight: 600;\n    letter-spacing: -0.005em;\n  }\n  .bl-feat-meta .author{\n    color: var(--heading);\n    font-weight: 700;\n  }\n  .bl-feat-meta .dot{\n    width: 3px; height: 3px;\n    border-radius: 50%;\n    background: var(--line-faint);\n  }\n\n  /* === RIGHT side: \"Latest\" feed === */\n  .bl-latest{\n    background: rgba(255,255,255,.45);\n    border: 1px solid var(--line-soft);\n    border-radius: 18px;\n    padding: clamp(20px, 2.2vw, 26px);\n    backdrop-filter: blur(10px);\n    -webkit-backdrop-filter: blur(10px);\n  }\n  .bl-latest-head{\n    display: flex; align-items: center; justify-content: space-between;\n    padding-bottom: 14px;\n    margin-bottom: 14px;\n    border-bottom: 1px solid var(--line-faint);\n  }\n  .bl-latest-title{\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: .24em;\n    text-transform: uppercase;\n    color: var(--heading);\n    display: inline-flex; align-items: center; gap: 8px;\n    margin: 0;\n  }\n  .bl-latest-title::before{\n    content:\"\"; width: 6px; height: 6px;\n    border-radius: 50%;\n    background: var(--cta);\n    animation: pulseDot 2.4s ease-in-out infinite;\n  }\n  .bl-latest-link{\n    font-size: 10.5px;\n    font-weight: 700;\n    letter-spacing: .14em;\n    text-transform: uppercase;\n    color: var(--line);\n    display: inline-flex; align-items: center; gap: 4px;\n    transition: color .2s, gap .25s;\n  }\n  .bl-latest-link:hover{ color: var(--cta); gap: 8px; }\n\n  .bl-latest-list{\n    display: flex; flex-direction: column;\n  }\n  .bl-latest-item{\n    display: grid;\n    grid-template-columns: 1fr 56px;\n    gap: 12px;\n    padding: 14px 0;\n    border-bottom: 1px solid var(--line-faint);\n    align-items: center;\n    text-decoration: none;\n    color: inherit;\n    transition: padding-left .25s, transform .25s;\n  }\n  .bl-latest-item:last-child{ border-bottom: 0; padding-bottom: 4px; }\n  .bl-latest-item:first-child{ padding-top: 4px; }\n  .bl-latest-item:hover{ padding-left: 4px; }\n\n  .bl-latest-body{ min-width: 0; }\n  .bl-latest-h{\n    font-size: 13px;\n    font-weight: 700;\n    letter-spacing: -0.012em;\n    color: var(--heading);\n    line-height: 1.3;\n    margin: 0 0 4px;\n    display: -webkit-box;\n    -webkit-line-clamp: 2;\n    -webkit-box-orient: vertical;\n    overflow: hidden;\n    transition: color .25s;\n  }\n  .bl-latest-item:hover .bl-latest-h{ color: var(--cta); }\n  .bl-latest-meta{\n    font-size: 10.5px;\n    font-weight: 600;\n    letter-spacing: -0.005em;\n    color: var(--muted);\n    line-height: 1.3;\n  }\n\n  .bl-latest-thumb{\n    width: 56px; height: 56px;\n    border-radius: 10px;\n    border: 1px solid var(--line-faint);\n    overflow: hidden;\n    position: relative;\n    flex: 0 0 56px;\n    isolation: isolate;\n    transition: border-color .25s, transform .35s;\n  }\n  .bl-latest-item:hover .bl-latest-thumb{\n    border-color: var(--line);\n    transform: scale(1.05);\n  }\n  .bl-latest-thumb svg{\n    position: absolute; inset: 0; margin: auto;\n    width: 56%; height: 56%;\n  }\n  /* Per-thumb backdrops */\n  .bl-latest-item:nth-child(1) .bl-latest-thumb{\n    background:\n      radial-gradient(60px 40px at 30% 30%, rgba(87,109,181,.30), transparent 60%),\n      radial-gradient(60px 40px at 75% 78%, rgba(143,188,143,.22), transparent 65%),\n      var(--bg-alt);\n  }\n  .bl-latest-item:nth-child(2) .bl-latest-thumb{\n    background:\n      radial-gradient(60px 40px at 30% 30%, rgba(143,188,143,.30), transparent 60%),\n      radial-gradient(60px 40px at 75% 78%, rgba(179,139,109,.22), transparent 65%),\n      var(--bg-alt);\n  }\n  .bl-latest-item:nth-child(3) .bl-latest-thumb{\n    background:\n      radial-gradient(60px 40px at 30% 30%, rgba(179,139,109,.28), transparent 60%),\n      radial-gradient(60px 40px at 75% 78%, rgba(87,109,181,.20), transparent 65%),\n      var(--bg-alt);\n  }\n  .bl-latest-item:nth-child(4) .bl-latest-thumb{\n    background:\n      radial-gradient(60px 40px at 30% 30%, rgba(87,109,181,.26), transparent 60%),\n      radial-gradient(60px 40px at 75% 78%, rgba(143,188,143,.20), transparent 65%),\n      var(--bg-alt);\n  }\n  .bl-latest-item:nth-child(5) .bl-latest-thumb{\n    background:\n      radial-gradient(60px 40px at 30% 30%, rgba(143,188,143,.28), transparent 60%),\n      radial-gradient(60px 40px at 75% 78%, rgba(179,139,109,.20), transparent 65%),\n      var(--bg-alt);\n  }\n\n  /* Trending topics row (between masthead and 3-col grid) */\n  .bl-hero-topics{\n    display: flex; flex-wrap: wrap; align-items: center; gap: 8px;\n    margin-bottom: clamp(28px, 3vw, 40px);\n    padding-bottom: clamp(20px, 2.4vw, 28px);\n    border-bottom: 1px solid var(--line-faint);\n  }\n  .bl-hero-topics-label{\n    font-size: 10.5px;\n    font-weight: 700;\n    letter-spacing: .22em;\n    text-transform: uppercase;\n    color: var(--muted);\n    margin-right: 6px;\n  }\n  .bl-hero-topic{\n    display: inline-flex; align-items: center; gap: 8px;\n    padding: 8px 14px 8px 12px;\n    background: rgba(255,255,255,.6);\n    border: 1px solid var(--line-soft);\n    border-radius: 999px;\n    font-size: 12px;\n    font-weight: 600;\n    color: var(--heading);\n    transition: border-color .25s, background .25s, color .25s, transform .2s;\n  }\n  .bl-hero-topic::before{\n    content:\"\"; width: 5px; height: 5px;\n    border-radius: 50%;\n    background: var(--cta);\n  }\n  .bl-hero-topic:nth-child(2)::before{ background: var(--accent-soft); }\n  .bl-hero-topic:nth-child(3n)::before{ background: var(--line); }\n  .bl-hero-topic:nth-child(5n)::before{ background: var(--accent-soft); }\n  .bl-hero-topic:hover{\n    border-color: var(--line);\n    background: #fff;\n    color: var(--cta);\n    transform: translateY(-1px);\n  }\n\n  /* Decorative reg marks */\n  .bl-hero-reg{\n    position: absolute;\n    width: 12px; height: 12px;\n    color: var(--line);\n    opacity: .5;\n    pointer-events: none;\n  }\n  .bl-hero-reg.tr{ top: 22px; right: 22px; border-top: 1px solid currentColor; border-right: 1px solid currentColor; }\n  .bl-hero-reg.bl{ bottom: 22px; left: 22px; border-bottom: 1px solid currentColor; border-left: 1px solid currentColor; }\n\n  /* ============ FEATURED ARTICLE ============ */\n  .bl-featured{\n    background: var(--bg);\n    padding: clamp(56px, 7vw, 96px) 0 clamp(32px, 4vw, 56px);\n    position: relative;\n  }\n  .bl-feat-card{\n    position: relative;\n    display: grid;\n    grid-template-columns: 1fr 1fr;\n    gap: 0;\n    background: rgba(255,255,255,.65);\n    backdrop-filter: blur(14px) saturate(140%);\n    -webkit-backdrop-filter: blur(14px) saturate(140%);\n    border: 1px solid var(--line-soft);\n    border-radius: 28px;\n    overflow: hidden;\n    isolation: isolate;\n    transition: border-color .35s, box-shadow .35s, background .35s, transform .35s;\n  }\n  .bl-feat-card::before{\n    content:\"\";\n    position: absolute;\n    top: 0; left: 0; right: 0;\n    height: 3px;\n    background: linear-gradient(90deg, var(--line) 0%, var(--accent-soft) 100%);\n    transform: scaleX(0);\n    transform-origin: left;\n    transition: transform .55s cubic-bezier(.2,.7,.2,1);\n    z-index: 3;\n  }\n  .bl-feat-card:hover{\n    transform: translateY(-3px);\n    border-color: var(--line);\n    background: #fff;\n    box-shadow: 0 36px 72px -36px rgba(179,139,109,.40);\n  }\n  .bl-feat-card:hover::before{ transform: scaleX(1); }\n\n  /* LEFT: visual — illustrated SVG cover */\n  .bl-feat-cover{\n    position: relative;\n    aspect-ratio: 4 / 3;\n    background:\n      radial-gradient(360px 220px at 30% 30%, rgba(143,188,143,.32), transparent 60%),\n      radial-gradient(420px 280px at 75% 78%, rgba(87,109,181,.22), transparent 65%),\n      var(--bg-alt);\n    overflow: hidden;\n    border-right: 1px solid var(--line-faint);\n  }\n  .bl-feat-cover::before{\n    content:\"\";\n    position: absolute; inset: 0;\n    background-image:\n      linear-gradient(rgba(45,55,72,.04) 1px, transparent 1px),\n      linear-gradient(90deg, rgba(45,55,72,.04) 1px, transparent 1px);\n    background-size: 32px 32px;\n    pointer-events: none;\n    opacity: .8;\n  }\n  .bl-feat-cover svg{\n    position: absolute;\n    inset: 0;\n    margin: auto;\n    width: 60%;\n    height: 60%;\n    transition: transform .55s cubic-bezier(.2,.7,.2,1);\n  }\n  .bl-feat-card:hover .bl-feat-cover svg{ transform: scale(1.04); }\n\n  .bl-feat-badge{\n    position: absolute;\n    top: 22px;\n    left: 22px;\n    z-index: 2;\n    display: inline-flex; align-items: center; gap: 8px;\n    padding: 7px 14px 7px 12px;\n    background: rgba(255,255,255,.92);\n    backdrop-filter: blur(10px);\n    border: 1px solid var(--line-soft);\n    border-radius: 999px;\n    font-size: 10.5px;\n    font-weight: 700;\n    letter-spacing: .22em;\n    text-transform: uppercase;\n    color: var(--heading);\n  }\n  .bl-feat-badge::before{\n    content:\"\"; width: 6px; height: 6px; border-radius: 50%;\n    background: var(--cta);\n  }\n\n  /* RIGHT: content */\n  .bl-feat-body{\n    padding: clamp(28px, 3vw, 48px);\n    display: flex; flex-direction: column;\n    gap: 18px;\n    justify-content: center;\n  }\n  .bl-feat-cat{\n    display: inline-flex; align-items: center; gap: 8px;\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: .22em;\n    text-transform: uppercase;\n    color: var(--line);\n    align-self: flex-start;\n  }\n  .bl-feat-cat::before{\n    content:\"\"; width: 6px; height: 6px; border-radius: 50%;\n    background: var(--accent-soft);\n  }\n  .bl-feat-title{\n    font-size: clamp(28px, 3.2vw, 42px);\n    font-weight: 700;\n    line-height: 1.1;\n    letter-spacing: -0.024em;\n    color: var(--heading);\n    margin: 0;\n    max-width: 22ch;\n  }\n  .bl-feat-excerpt{\n    font-size: 15px;\n    line-height: 1.65;\n    color: var(--body);\n    margin: 0;\n    max-width: 56ch;\n    font-weight: 500;\n  }\n  .bl-feat-meta{\n    display: flex; flex-wrap: wrap; align-items: center; gap: 14px;\n    padding-top: 16px;\n    border-top: 1px solid var(--line-faint);\n    margin-top: 8px;\n  }\n  .bl-author{\n    display: flex; align-items: center; gap: 10px;\n  }\n  .bl-author-avatar{\n    width: 36px; height: 36px;\n    border-radius: 50%;\n    background:\n      radial-gradient(circle at 30% 30%, rgba(87,109,181,.30), transparent 65%),\n      radial-gradient(circle at 70% 70%, rgba(143,188,143,.22), transparent 65%),\n      var(--bg-alt);\n    border: 1px solid var(--line-faint);\n    display: grid; place-items: center;\n    flex: 0 0 36px;\n  }\n  .bl-author-avatar svg{ width: 18px; height: 18px; color: var(--cta); }\n  .bl-author-text{\n    display: flex; flex-direction: column; gap: 1px;\n  }\n  .bl-author-name{\n    font-size: 12.5px;\n    font-weight: 700;\n    color: var(--heading);\n    letter-spacing: -0.008em;\n    line-height: 1.2;\n  }\n  .bl-author-role{\n    font-size: 10.5px;\n    color: var(--muted);\n    font-weight: 500;\n  }\n  .bl-feat-meta .dot{\n    width: 3px; height: 3px;\n    border-radius: 50%;\n    background: var(--line-faint);\n  }\n  .bl-feat-meta-item{\n    display: inline-flex; align-items: center; gap: 6px;\n    font-size: 12px;\n    color: var(--muted);\n    font-weight: 500;\n  }\n  .bl-feat-meta-item svg{ color: var(--line); }\n  .bl-feat-cta{\n    display: inline-flex; align-items: center; gap: 12px;\n    padding: 14px 8px 14px 22px;\n    background: var(--cta);\n    color: #fff;\n    font-size: 14px;\n    font-weight: 600;\n    border-radius: 999px;\n    align-self: flex-start;\n    margin-top: 8px;\n    box-shadow:\n      0 1px 0 rgba(255,255,255,.20) inset,\n      0 12px 32px -10px rgba(87,109,181,.50);\n    transition: transform .2s, background .2s, box-shadow .25s;\n  }\n  .bl-feat-cta:hover{\n    background: var(--cta-hover);\n    transform: translateY(-2px);\n    box-shadow:\n      0 1px 0 rgba(255,255,255,.20) inset,\n      0 18px 42px -10px rgba(87,109,181,.65);\n  }\n  .bl-feat-cta .ico{\n    width: 30px; height: 30px;\n    border-radius: 50%;\n    background: rgba(255,255,255,.20);\n    display: grid; place-items: center;\n    flex: 0 0 30px;\n    transition: background .25s, transform .3s;\n  }\n  .bl-feat-cta:hover .ico{ background: rgba(255,255,255,.30); transform: rotate(-12deg); }\n\n  /* ============ PROCESS TIMELINE (after hero) ============ */\n  .bl-process{\n    position: relative;\n    background: var(--bg);\n    padding: clamp(72px, 9vw, 120px) 0;\n    border-top: 1px solid var(--line-faint);\n    overflow: hidden;\n  }\n  .bl-process::before{\n    content:\"\";\n    position: absolute; inset: 0;\n    background:\n      radial-gradient(700px 380px at 8% 10%, rgba(143,188,143,.08), transparent 70%),\n      radial-gradient(620px 320px at 92% 90%, rgba(179,139,109,.06), transparent 70%);\n    pointer-events: none;\n  }\n\n  .bl-process-head{\n    display: grid;\n    grid-template-columns: repeat(12, 1fr);\n    gap: var(--gutter);\n    align-items: end;\n    margin-bottom: clamp(56px, 7vw, 96px);\n    position: relative;\n  }\n  .bl-process-eyebrow{\n    grid-column: 1 / -1;\n    display: inline-flex; align-items: center; gap: 10px;\n    padding: 8px 16px;\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: .24em;\n    text-transform: uppercase;\n    color: var(--muted);\n    background: rgba(143,188,143,.18);\n    border: 1px solid rgba(143,188,143,.40);\n    border-radius: 999px;\n    max-width: max-content;\n    margin-bottom: 22px;\n  }\n  .bl-process-eyebrow::before{\n    content:\"\"; width: 6px; height: 6px; border-radius: 50%;\n    background: var(--accent-soft);\n  }\n  .bl-process-h2{\n    grid-column: 1 / span 7;\n    font-size: clamp(32px, 4.4vw, 56px);\n    line-height: 1.04;\n    letter-spacing: -0.028em;\n    color: var(--heading);\n    font-weight: 700;\n    margin: 0;\n    max-width: 18ch;\n    text-wrap: balance;\n  }\n  .bl-process-sub{\n    grid-column: 8 / -1;\n    font-size: 15px;\n    line-height: 1.65;\n    color: var(--body);\n    margin: 0;\n    padding-bottom: 8px;\n    max-width: 38ch;\n    font-weight: 500;\n  }\n\n  /* Range marker (top right) */\n  .bl-process-range{\n    position: absolute;\n    top: -10px;\n    right: 0;\n    display: flex; align-items: center; gap: 4px;\n  }\n  .bl-process-range-pill{\n    padding: 7px 12px;\n    background: var(--bg-alt);\n    border: 1px solid var(--line-faint);\n    border-radius: 8px;\n    font-size: 10.5px;\n    font-weight: 700;\n    letter-spacing: .14em;\n    text-transform: uppercase;\n    color: var(--muted);\n  }\n  .bl-process-range-pill.is-end{\n    background: rgba(143,188,143,.30);\n    border-color: rgba(143,188,143,.50);\n    color: var(--heading);\n  }\n\n  /* Steps container */\n  .bl-steps{\n    position: relative;\n    max-width: 920px;\n    margin: 0 auto;\n  }\n\n  .bl-step{\n    position: relative;\n    display: grid;\n    grid-template-columns: 76px 1fr;\n    gap: 0;\n    margin-bottom: clamp(24px, 3vw, 36px);\n    align-items: stretch;\n  }\n  .bl-step:last-child{ margin-bottom: 0; }\n\n  /* Zigzag offsetting */\n  .bl-step.s1{ margin-left: 0; margin-right: 50%; }\n  .bl-step.s2{ margin-left: 25%; margin-right: 18%; }\n  .bl-step.s3{ margin-left: 12%; margin-right: 35%; }\n  .bl-step.s4{ margin-left: 40%; margin-right: 0; }\n\n  /* Connector dashed line — between steps */\n  .bl-step::before{\n    content:\"\";\n    position: absolute;\n    width: 1px;\n    background-image: linear-gradient(to bottom, var(--line) 50%, transparent 50%);\n    background-size: 1px 8px;\n    background-repeat: repeat-y;\n    z-index: 0;\n  }\n  .bl-step.s1::before{\n    bottom: -36px;\n    right: -25%;\n    height: 36px;\n    width: 25%;\n    background-image: none;\n    border-bottom: 1px dashed var(--line);\n    border-right: 1px dashed var(--line);\n    border-bottom-right-radius: 16px;\n    background: transparent;\n    height: 70px;\n    bottom: -50px;\n  }\n  /* Simplified — use ::after on each card foot for cleaner connector */\n  .bl-step.s1::before, .bl-step.s2::before, .bl-step.s3::before{\n    display: none;\n  }\n\n  /* LEFT: badge column */\n  .bl-step-badge{\n    position: relative;\n    background: #1F2A44;\n    border-radius: 16px 0 0 16px;\n    padding: clamp(20px, 2.4vw, 28px) 12px;\n    display: flex; flex-direction: column;\n    align-items: center; justify-content: center;\n    flex: 0 0 76px;\n    min-height: 100%;\n    overflow: hidden;\n  }\n  .bl-step-badge::before{\n    content:\"\";\n    position: absolute; inset: 0;\n    background:\n      radial-gradient(80px 60px at 50% 20%, rgba(143,188,143,.20), transparent 70%);\n    pointer-events: none;\n  }\n  .bl-step-badge-text{\n    position: relative;\n    color: #fff;\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: .16em;\n    text-transform: uppercase;\n    writing-mode: vertical-rl;\n    transform: rotate(180deg);\n    line-height: 1;\n    white-space: nowrap;\n  }\n\n  /* RIGHT: content card */\n  .bl-step-card{\n    position: relative;\n    background: rgba(143,188,143,.12);\n    backdrop-filter: blur(10px);\n    -webkit-backdrop-filter: blur(10px);\n    border: 1px solid rgba(143,188,143,.30);\n    border-left: 0;\n    border-radius: 0 16px 16px 0;\n    padding: clamp(20px, 2.4vw, 28px) clamp(22px, 2.6vw, 32px);\n    display: flex; flex-direction: column;\n    gap: 10px;\n    transition: border-color .35s, background .35s, box-shadow .35s, transform .3s;\n  }\n  .bl-step:hover .bl-step-card{\n    transform: translateY(-3px);\n    border-color: var(--line);\n    background: rgba(255,255,255,.85);\n    box-shadow: 0 24px 48px -28px rgba(179,139,109,.40);\n  }\n  .bl-step:hover .bl-step-badge{\n    background: #0F1822;\n  }\n\n  .bl-step-head{\n    display: flex; align-items: center; gap: 12px;\n  }\n  .bl-step-ico{\n    width: 28px; height: 28px;\n    border-radius: 8px;\n    background: rgba(255,255,255,.7);\n    color: var(--heading);\n    display: grid; place-items: center;\n    flex: 0 0 28px;\n    border: 1px solid rgba(143,188,143,.35);\n    transition: transform .35s, background .25s;\n  }\n  .bl-step:hover .bl-step-ico{ transform: rotate(-6deg) scale(1.06); }\n  .bl-step-num{\n    font-size: clamp(18px, 1.8vw, 22px);\n    font-weight: 700;\n    color: var(--heading);\n    letter-spacing: -0.02em;\n    line-height: 1;\n  }\n  .bl-step-title{\n    font-size: clamp(18px, 1.8vw, 22px);\n    font-weight: 700;\n    color: var(--heading);\n    letter-spacing: -0.02em;\n    line-height: 1.2;\n    margin: 0;\n  }\n  .bl-step-text{\n    font-size: 14px;\n    line-height: 1.6;\n    color: var(--body);\n    margin: 0;\n    max-width: 56ch;\n    font-weight: 500;\n  }\n\n  /* Connector dashed L-paths between zigzag steps */\n  .bl-step-conn{\n    position: absolute;\n    pointer-events: none;\n    z-index: 0;\n  }\n  .bl-step.s1 .bl-step-conn{\n    bottom: -34px;\n    left: 50%;\n    width: 35%;\n    height: 36px;\n    border-left: 1px dashed var(--line);\n    border-bottom: 1px dashed var(--line);\n    border-bottom-left-radius: 14px;\n  }\n  .bl-step.s2 .bl-step-conn{\n    bottom: -34px;\n    right: 60%;\n    width: 35%;\n    height: 36px;\n    border-right: 1px dashed var(--line);\n    border-bottom: 1px dashed var(--line);\n    border-bottom-right-radius: 14px;\n  }\n  .bl-step.s3 .bl-step-conn{\n    bottom: -34px;\n    left: 50%;\n    width: 35%;\n    height: 36px;\n    border-left: 1px dashed var(--line);\n    border-bottom: 1px dashed var(--line);\n    border-bottom-left-radius: 14px;\n  }\n\n  /* Final step accents */\n  .bl-step.s4 .bl-step-card{\n    background: rgba(143,188,143,.20);\n    border-color: rgba(143,188,143,.45);\n  }\n  .bl-step.s4::after{\n    content:\"\";\n    position: absolute;\n    top: -38px; right: 38px;\n    width: 22px; height: 22px;\n    border: 1px solid var(--line);\n    border-radius: 50%;\n    display: grid; place-items: center;\n  }\n  .bl-step-spark{\n    position: absolute;\n    top: -38px; right: 0;\n    width: 22px; height: 22px;\n    color: var(--line);\n  }\n  .bl-step-expand{\n    position: absolute;\n    top: 18px; right: 18px;\n    width: 28px; height: 28px;\n    border: 1px solid rgba(143,188,143,.40);\n    border-radius: 6px;\n    background: rgba(255,255,255,.7);\n    color: var(--heading);\n    display: grid; place-items: center;\n    transition: transform .3s, border-color .25s, background .25s;\n  }\n  .bl-step:hover .bl-step-expand{\n    transform: rotate(45deg);\n    border-color: var(--line);\n    background: #fff;\n  }\n\n  /* ============ FILTER + SEARCH ============ */\n  .bl-tools{\n    background: var(--bg);\n    padding: clamp(28px, 3vw, 48px) 0;\n    border-top: 1px solid var(--line-faint);\n    border-bottom: 1px solid var(--line-faint);\n    position: relative;\n  }\n  .bl-tools-grid{\n    display: grid;\n    grid-template-columns: 1fr auto;\n    gap: clamp(16px, 2vw, 28px);\n    align-items: center;\n  }\n  .bl-cats{\n    display: flex; flex-wrap: wrap; gap: 8px;\n    align-items: center;\n  }\n  .bl-cat{\n    display: inline-flex; align-items: center; gap: 8px;\n    padding: 9px 16px;\n    background: rgba(255,255,255,.6);\n    border: 1px solid var(--line-soft);\n    border-radius: 999px;\n    font-family: inherit;\n    font-size: 12.5px;\n    font-weight: 600;\n    letter-spacing: .02em;\n    color: var(--body);\n    cursor: pointer;\n    transition: border-color .25s, background .25s, color .25s, transform .2s;\n  }\n  .bl-cat .count{\n    font-size: 10.5px;\n    font-weight: 700;\n    color: var(--muted);\n    padding: 2px 7px;\n    background: rgba(45,55,72,.06);\n    border-radius: 999px;\n    transition: background .25s, color .25s;\n  }\n  .bl-cat:hover{\n    border-color: var(--line);\n    background: #fff;\n    color: var(--heading);\n    transform: translateY(-1px);\n  }\n  .bl-cat.is-active{\n    background: var(--cta);\n    border-color: var(--cta);\n    color: #fff;\n  }\n  .bl-cat.is-active .count{\n    background: rgba(255,255,255,.20);\n    color: #fff;\n  }\n\n  .bl-search{\n    position: relative;\n    width: clamp(220px, 28vw, 340px);\n  }\n  .bl-search input{\n    width: 100%;\n    padding: 12px 16px 12px 42px;\n    background: rgba(255,255,255,.65);\n    border: 1px solid var(--line-soft);\n    border-radius: 999px;\n    font-family: inherit;\n    font-size: 13.5px;\n    color: var(--heading);\n    outline: none;\n    transition: border-color .2s, background .2s, box-shadow .2s;\n  }\n  .bl-search input::placeholder{ color: var(--muted); }\n  .bl-search input:focus{\n    border-color: var(--cta);\n    background: #fff;\n    box-shadow: 0 0 0 3px rgba(87,109,181,.10);\n  }\n  .bl-search svg{\n    position: absolute;\n    left: 14px; top: 50%;\n    transform: translateY(-50%);\n    color: var(--muted);\n    pointer-events: none;\n  }\n\n  /* ============ ARTICLE GRID ============ */\n  .bl-grid-section{\n    background: var(--bg);\n    padding: clamp(56px, 7vw, 96px) 0 clamp(72px, 9vw, 128px);\n    position: relative;\n  }\n\n  .bl-grid{\n    display: grid;\n    grid-template-columns: repeat(3, 1fr);\n    gap: clamp(20px, 2.4vw, 28px);\n  }\n\n  .bl-card{\n    position: relative;\n    display: flex; flex-direction: column;\n    background: rgba(255,255,255,.65);\n    backdrop-filter: blur(12px) saturate(140%);\n    -webkit-backdrop-filter: blur(12px) saturate(140%);\n    border: 1px solid var(--line-soft);\n    border-radius: 22px;\n    overflow: hidden;\n    isolation: isolate;\n    transition: transform .35s cubic-bezier(.2,.7,.2,1), border-color .3s, box-shadow .3s, background .3s;\n    text-decoration: none;\n    color: inherit;\n  }\n  .bl-card::before{\n    content:\"\";\n    position: absolute;\n    top: 0; left: 0; right: 0;\n    height: 3px;\n    background: linear-gradient(90deg, var(--line) 0%, var(--accent-soft) 100%);\n    transform: scaleX(0);\n    transform-origin: left;\n    transition: transform .45s cubic-bezier(.2,.7,.2,1);\n    z-index: 2;\n  }\n  .bl-card:hover{\n    transform: translateY(-6px);\n    border-color: var(--line);\n    background: #fff;\n    box-shadow: 0 36px 72px -36px rgba(179,139,109,.40);\n  }\n  .bl-card:hover::before{ transform: scaleX(1); }\n\n  .bl-card-cover{\n    position: relative;\n    aspect-ratio: 16 / 10;\n    overflow: hidden;\n    border-bottom: 1px solid var(--line-faint);\n  }\n  .bl-card-cover svg{\n    position: absolute;\n    inset: 0;\n    margin: auto;\n    width: 50%;\n    height: 50%;\n    transition: transform .55s cubic-bezier(.2,.7,.2,1);\n  }\n  .bl-card:hover .bl-card-cover svg{ transform: scale(1.08); }\n\n  /* Per-card backdrop colors (rotate for visual rhythm) */\n  .bl-card:nth-child(3n+1) .bl-card-cover{\n    background:\n      radial-gradient(280px 180px at 30% 30%, rgba(143,188,143,.32), transparent 60%),\n      radial-gradient(320px 220px at 75% 78%, rgba(87,109,181,.20), transparent 65%),\n      var(--bg-alt);\n  }\n  .bl-card:nth-child(3n+2) .bl-card-cover{\n    background:\n      radial-gradient(280px 180px at 30% 30%, rgba(87,109,181,.26), transparent 60%),\n      radial-gradient(320px 220px at 75% 78%, rgba(179,139,109,.20), transparent 65%),\n      var(--bg-alt);\n  }\n  .bl-card:nth-child(3n+3) .bl-card-cover{\n    background:\n      radial-gradient(280px 180px at 30% 30%, rgba(179,139,109,.28), transparent 60%),\n      radial-gradient(320px 220px at 75% 78%, rgba(143,188,143,.22), transparent 65%),\n      var(--bg-alt);\n  }\n\n  .bl-card-cover::before{\n    content:\"\";\n    position: absolute; inset: 0;\n    background-image:\n      linear-gradient(rgba(45,55,72,.04) 1px, transparent 1px),\n      linear-gradient(90deg, rgba(45,55,72,.04) 1px, transparent 1px);\n    background-size: 24px 24px;\n    pointer-events: none;\n    opacity: .7;\n  }\n\n  .bl-card-cat{\n    position: absolute;\n    top: 16px; left: 16px;\n    z-index: 2;\n    display: inline-flex; align-items: center; gap: 6px;\n    padding: 6px 12px 6px 10px;\n    background: rgba(255,255,255,.92);\n    backdrop-filter: blur(10px);\n    border: 1px solid var(--line-soft);\n    border-radius: 999px;\n    font-size: 10px;\n    font-weight: 700;\n    letter-spacing: .22em;\n    text-transform: uppercase;\n    color: var(--heading);\n  }\n  .bl-card-cat::before{\n    content:\"\"; width: 5px; height: 5px; border-radius: 50%;\n    background: var(--cta);\n  }\n  .bl-card:nth-child(3n+2) .bl-card-cat::before{ background: var(--accent-soft); }\n  .bl-card:nth-child(3n+3) .bl-card-cat::before{ background: var(--line); }\n\n  .bl-card-body{\n    padding: clamp(20px, 2.2vw, 28px);\n    display: flex; flex-direction: column; gap: 12px;\n    flex: 1;\n  }\n\n  .bl-card-meta-top{\n    display: flex; align-items: center; gap: 10px;\n    font-size: 11px;\n    font-weight: 600;\n    color: var(--muted);\n    letter-spacing: -0.005em;\n  }\n  .bl-card-meta-top .dot{\n    width: 3px; height: 3px;\n    border-radius: 50%;\n    background: var(--line-faint);\n  }\n  .bl-card-meta-top .item{\n    display: inline-flex; align-items: center; gap: 5px;\n  }\n  .bl-card-meta-top svg{ color: var(--line); }\n\n  .bl-card-title{\n    font-size: clamp(17px, 1.6vw, 21px);\n    font-weight: 700;\n    line-height: 1.25;\n    letter-spacing: -0.014em;\n    color: var(--heading);\n    margin: 0;\n    max-width: 22ch;\n    transition: color .25s;\n  }\n  .bl-card:hover .bl-card-title{ color: var(--cta); }\n\n  .bl-card-excerpt{\n    font-size: 13.5px;\n    line-height: 1.6;\n    color: var(--body);\n    margin: 0;\n    font-weight: 500;\n    max-width: 50ch;\n  }\n\n  .bl-card-foot{\n    display: flex; align-items: center; justify-content: space-between;\n    padding-top: 14px;\n    margin-top: auto;\n    border-top: 1px solid var(--line-faint);\n  }\n  .bl-card-author{\n    display: inline-flex; align-items: center; gap: 8px;\n  }\n  .bl-card-author-avatar{\n    width: 26px; height: 26px;\n    border-radius: 50%;\n    background:\n      radial-gradient(circle at 30% 30%, rgba(87,109,181,.30), transparent 65%),\n      radial-gradient(circle at 70% 70%, rgba(143,188,143,.22), transparent 65%),\n      var(--bg-alt);\n    border: 1px solid var(--line-faint);\n    display: grid; place-items: center;\n    flex: 0 0 26px;\n  }\n  .bl-card-author-avatar svg{ width: 13px; height: 13px; color: var(--cta); }\n  .bl-card-author-name{\n    font-size: 12px;\n    font-weight: 700;\n    color: var(--heading);\n    letter-spacing: -0.005em;\n  }\n  .bl-card-cta{\n    display: inline-flex; align-items: center; gap: 4px;\n    font-size: 12px;\n    font-weight: 700;\n    color: var(--line);\n    letter-spacing: -0.005em;\n    transition: color .25s, gap .3s;\n  }\n  .bl-card:hover .bl-card-cta{ color: var(--cta); gap: 8px; }\n  .bl-card-cta svg{ transition: transform .35s; }\n  .bl-card:hover .bl-card-cta svg{ transform: translateX(2px); }\n\n  /* Pagination */\n  .bl-pagination{\n    display: flex; align-items: center; justify-content: center;\n    gap: 8px;\n    margin-top: clamp(48px, 6vw, 72px);\n    padding-top: clamp(36px, 4vw, 56px);\n    border-top: 1px solid var(--line-faint);\n  }\n  .bl-pg-btn{\n    display: inline-flex; align-items: center; justify-content: center;\n    min-width: 40px; height: 40px;\n    padding: 0 10px;\n    background: rgba(255,255,255,.6);\n    border: 1px solid var(--line-soft);\n    border-radius: 999px;\n    font-family: inherit;\n    font-size: 13px;\n    font-weight: 600;\n    color: var(--body);\n    cursor: pointer;\n    transition: border-color .25s, background .25s, color .25s;\n  }\n  .bl-pg-btn:hover{\n    border-color: var(--line);\n    background: #fff;\n    color: var(--heading);\n  }\n  .bl-pg-btn.is-active{\n    background: var(--cta);\n    border-color: var(--cta);\n    color: #fff;\n  }\n  .bl-pg-btn:disabled{\n    opacity: .35; cursor: not-allowed;\n  }\n  .bl-pg-arrow{\n    width: 40px; height: 40px;\n    padding: 0;\n  }\n\n  /* ============ NEWSLETTER STRIP ============ */\n  .bl-news{\n    background: var(--bg-alt);\n    padding: clamp(56px, 7vw, 96px) 0;\n    border-top: 1px solid var(--line-faint);\n    position: relative;\n    overflow: hidden;\n  }\n  .bl-news::before{\n    content:\"\";\n    position: absolute; inset: 0;\n    background:\n      radial-gradient(700px 380px at 92% 8%, rgba(143,188,143,.06), transparent 70%),\n      radial-gradient(620px 320px at 8% 94%, rgba(179,139,109,.05), transparent 70%);\n    pointer-events: none;\n  }\n\n  .bl-news-card{\n    position: relative;\n    border-radius: 28px;\n    overflow: hidden;\n    isolation: isolate;\n    padding: clamp(44px, 6vw, 80px) clamp(28px, 4vw, 64px);\n    background: linear-gradient(180deg, #2D3748 0%, #1F2837 100%);\n    box-shadow: 0 40px 100px -50px rgba(45,55,72,.40);\n  }\n  .bl-news-card::before{\n    content:\"\";\n    position: absolute; inset: 0;\n    background:\n      radial-gradient(680px 360px at 88% 12%, rgba(143,188,143,.18), transparent 70%),\n      radial-gradient(620px 320px at 8% 92%, rgba(179,139,109,.14), transparent 70%);\n    pointer-events: none;\n    z-index: 0;\n  }\n  .bl-news-card > *{ position: relative; z-index: 1; }\n\n  .bl-news-grid{\n    display: grid;\n    grid-template-columns: 1.2fr 1fr;\n    gap: clamp(28px, 4vw, 64px);\n    align-items: center;\n  }\n\n  .bl-news-eyebrow{\n    display: inline-flex; align-items: center; gap: 10px;\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: .24em;\n    text-transform: uppercase;\n    color: rgba(255,255,255,.70);\n    margin-bottom: 16px;\n  }\n  .bl-news-eyebrow::before{\n    content:\"\"; width: 7px; height: 7px; border-radius: 50%;\n    background: var(--accent-soft);\n    box-shadow: 0 0 0 5px rgba(143,188,143,.22);\n  }\n  .bl-news-h2{\n    font-size: clamp(28px, 3.4vw, 44px);\n    line-height: 1.06;\n    letter-spacing: -0.025em;\n    color: #fff;\n    font-weight: 700;\n    margin: 0 0 14px;\n    max-width: 18ch;\n  }\n  .bl-news-text{\n    font-size: 15px;\n    line-height: 1.65;\n    color: rgba(255,255,255,.78);\n    margin: 0;\n    max-width: 56ch;\n  }\n\n  .bl-news-form{\n    display: flex; flex-direction: column; gap: 12px;\n    width: 100%;\n  }\n  .bl-news-form input{\n    width: 100%;\n    padding: 16px 22px;\n    background: rgba(255,255,255,.92);\n    border: 1px solid rgba(255,255,255,.20);\n    border-radius: 999px;\n    font-family: inherit;\n    font-size: 14.5px;\n    font-weight: 500;\n    color: var(--heading);\n    outline: none;\n    transition: background .2s, border-color .2s;\n  }\n  .bl-news-form input::placeholder{ color: var(--muted); }\n  .bl-news-form input:focus{\n    background: #fff;\n    border-color: rgba(255,255,255,.6);\n  }\n  .bl-news-form button{\n    display: inline-flex; align-items: center; justify-content: center; gap: 12px;\n    padding: 16px 22px;\n    background: var(--cta);\n    color: #fff;\n    font-family: inherit;\n    font-size: 14.5px;\n    font-weight: 600;\n    border-radius: 999px;\n    cursor: pointer;\n    box-shadow:\n      0 1px 0 rgba(255,255,255,.20) inset,\n      0 12px 32px -10px rgba(87,109,181,.50);\n    transition: transform .2s, background .2s, box-shadow .25s;\n  }\n  .bl-news-form button:hover{\n    background: var(--cta-hover);\n    transform: translateY(-2px);\n    box-shadow:\n      0 1px 0 rgba(255,255,255,.20) inset,\n      0 18px 42px -10px rgba(87,109,181,.65);\n  }\n  .bl-news-form button svg{ transition: transform .35s; }\n  .bl-news-form button:hover svg{ transform: translateX(2px); }\n  .bl-news-disclaimer{\n    font-size: 11px;\n    color: rgba(255,255,255,.55);\n    margin: 4px 0 0;\n    line-height: 1.5;\n  }\n\n  /* Reveal */\n  .reveal{ opacity: 0; transform: translateY(14px); animation: rise .9s cubic-bezier(.2,.7,.2,1) forwards; }\n  .reveal.d1{ animation-delay: .05s; }\n  .reveal.d2{ animation-delay: .15s; }\n  .reveal.d3{ animation-delay: .25s; }\n  @keyframes rise{ to { opacity: 1; transform: none; } }\n\n  /* Responsive */\n  @media (max-width: 1100px){\n    .bl-grid{ grid-template-columns: repeat(2, 1fr); }\n    .bl-edit-grid{ grid-template-columns: 1fr 1fr; gap: clamp(20px, 2.4vw, 28px); }\n    .bl-feat{ grid-column: 1 / -1; order: -1; }\n    .bl-side:nth-child(1){ order: 1; }\n    .bl-side:nth-child(3){ order: 2; }\n    .bl-feat-cover{ aspect-ratio: 16 / 9; }\n    /* Process — soften zigzag */\n    .bl-step.s1{ margin-left: 0; margin-right: 25%; }\n    .bl-step.s2{ margin-left: 12%; margin-right: 12%; }\n    .bl-step.s3{ margin-left: 8%; margin-right: 18%; }\n    .bl-step.s4{ margin-left: 22%; margin-right: 0; }\n  }\n  @media (max-width: 1024px){\n    .menu{ display: none; }\n    .bl-mast-h1{ grid-column: 1 / -1; }\n    .bl-mast-lede{ grid-column: 1 / -1; padding-top: 14px; padding-bottom: 0; max-width: 56ch; }\n    .bl-tools-grid{ grid-template-columns: 1fr; }\n    .bl-search{ width: 100%; }\n    .bl-news-grid{ grid-template-columns: 1fr; }\n    .bl-process-h2, .bl-process-sub{ grid-column: 1 / -1; }\n    .bl-process-sub{ padding-top: 14px; padding-bottom: 0; }\n    .bl-process-range{ position: static; margin-top: 18px; }\n  }\n  @media (max-width: 720px){\n    .bl-grid{ grid-template-columns: 1fr; }\n    .bl-edit-grid{ grid-template-columns: 1fr; }\n    .bl-side{ flex-direction: column; }\n    .bl-cats{ overflow-x: auto; flex-wrap: nowrap; padding-bottom: 4px; -webkit-overflow-scrolling: touch; }\n    .bl-cat{ flex: 0 0 auto; }\n    .bl-pg-btn{ min-width: 36px; height: 36px; font-size: 12px; }\n    .bl-trail{ font-size: 11px; }\n    .bl-feat-cover{ aspect-ratio: 16 / 11; }\n    .bl-feat-title{ font-size: clamp(22px, 5vw, 28px); }\n    /* Process — full flat */\n    .bl-step.s1, .bl-step.s2, .bl-step.s3, .bl-step.s4{\n      margin-left: 0; margin-right: 0;\n    }\n    .bl-step-conn{ display: none; }\n    .bl-step{ grid-template-columns: 60px 1fr; }\n    .bl-step-badge{ flex-basis: 60px; }\n  }\n  @media (max-width: 640px){\n    .nav{ height: 64px; gap: 12px; }\n    .logo img{ height: 30px; }\n    .lang{ display: none; }\n  }\n\n/* ============ FOOTER ============ */\n  .footer{\n    position:relative;\n    background:\n      linear-gradient(180deg, rgba(248,249,250,.4), rgba(248,249,250,.95)),\n      radial-gradient(800px 420px at 88% 10%, rgba(143,188,143,.10), transparent 70%),\n      radial-gradient(720px 380px at 8% 92%, rgba(179,139,109,.08), transparent 70%),\n      var(--bg);\n    border-top: 1px solid var(--line-soft);\n    padding: clamp(72px, 9vw, 112px) 0 28px;\n    backdrop-filter: blur(14px) saturate(140%);\n    -webkit-backdrop-filter: blur(14px) saturate(140%);\n  }\n\n  .ft-grid{\n    display:grid;\n    grid-template-columns: 1.4fr 1fr 1fr 1.4fr;\n    gap: clamp(32px, 4vw, 56px) clamp(24px, 3vw, 40px);\n    position: relative;\n  }\n\n  /* Brand block */\n  .ft-brand{\n    display:flex; flex-direction:column;\n    gap: 22px;\n    max-width: 360px;\n  }\n  .ft-logo{ display:inline-block; }\n  .ft-logo img{\n    height: 38px;\n    width: auto;\n    display:block;\n  }\n  .ft-desc{\n    font-size: 14px;\n    line-height: 1.65;\n    color: var(--body);\n    margin: 0;\n    max-width: 38ch;\n  }\n  .ft-social{\n    display:flex; gap: 10px;\n    margin-top: 4px;\n  }\n  .ft-social a{\n    width: 40px; height: 40px;\n    border-radius: 50%;\n    display:grid; place-items:center;\n    border: 1px solid var(--line-soft);\n    background: rgba(255,255,255,.55);\n    backdrop-filter: blur(10px);\n    -webkit-backdrop-filter: blur(10px);\n    color: var(--heading);\n    transition: background .25s, border-color .25s, color .25s, transform .25s;\n  }\n  .ft-social a:hover{\n    background: var(--line);\n    border-color: var(--line);\n    color: #fff;\n    transform: translateY(-2px);\n  }\n\n  /* Link columns */\n  .ft-col{\n    display:flex; flex-direction:column;\n    gap: 18px;\n  }\n  .ft-h{\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: .22em;\n    text-transform: uppercase;\n    color: var(--heading);\n    margin: 0;\n    display:inline-flex; align-items:center; gap:8px;\n  }\n  .ft-h::before{\n    content:\"\"; width:5px; height:5px; border-radius:50%;\n    background: var(--line);\n  }\n  .ft-list{\n    list-style:none;\n    margin:0; padding:0;\n    display:flex; flex-direction:column;\n    gap: 11px;\n  }\n  .ft-list a,\n  .ft-list .ft-text{\n    font-size: 13.5px;\n    line-height: 1.5;\n    color: var(--body);\n    text-decoration: none;\n    position: relative;\n    transition: color .2s;\n    display: inline-block;\n  }\n  .ft-list a::after{\n    content:\"\";\n    position:absolute;\n    left: 0; bottom: -2px;\n    width: 0; height: 1px;\n    background: var(--line);\n    transition: width .25s ease;\n  }\n  .ft-list a:hover{ color: var(--heading); }\n  .ft-list a:hover::after{ width: 100%; }\n\n  .ft-list .ft-text{ color: var(--body); }\n  .ft-list a.ft-text-link{ color: var(--body); }\n\n  /* Newsletter */\n  .ft-news{\n    margin-top: 8px;\n    padding-top: 22px;\n    border-top: 1px solid var(--line-faint);\n  }\n  .ft-news-h{\n    font-size: 14px;\n    font-weight: 700;\n    color: var(--heading);\n    margin: 0 0 6px;\n    letter-spacing: -0.01em;\n  }\n  .ft-news-p{\n    font-size: 12.5px;\n    color: var(--muted);\n    margin: 0 0 14px;\n    line-height: 1.5;\n  }\n  .ft-form{\n    display:flex; align-items:center;\n    background: rgba(255,255,255,.6);\n    backdrop-filter: blur(10px);\n    -webkit-backdrop-filter: blur(10px);\n    border: 1px solid var(--line-soft);\n    border-radius: 999px;\n    padding: 4px 4px 4px 6px;\n    gap: 4px;\n    transition: border-color .25s, background .25s;\n  }\n  .ft-form:focus-within{\n    border-color: var(--line);\n    background: #fff;\n  }\n  .ft-form input{\n    flex: 1;\n    border: 0;\n    background: transparent;\n    padding: 10px 14px;\n    font-size: 13px;\n    font-family: inherit;\n    color: var(--heading);\n    outline: 0;\n    min-width: 0;\n  }\n  .ft-form input::placeholder{ color: var(--muted); }\n  .ft-form button{\n    padding: 10px 18px;\n    border-radius: 999px;\n    background: var(--cta);\n    color: #fff;\n    font-size: 12.5px;\n    font-weight: 600;\n    letter-spacing: .02em;\n    cursor: pointer;\n    border: 0;\n    display:inline-flex; align-items:center; gap: 6px;\n    flex: 0 0 auto;\n    transition: background .2s, transform .15s;\n  }\n  .ft-form button:hover{ background: var(--cta-hover); transform: translateY(-1px); }\n\n  /* Bottom row */\n  .ft-bottom{\n    margin-top: clamp(56px, 7vw, 80px);\n    padding-top: 22px;\n    border-top: 1px solid var(--line-faint);\n    display:flex; justify-content:space-between; align-items:center;\n    gap: 16px;\n    flex-wrap: wrap;\n    font-size: 12.5px;\n    color: var(--muted);\n  }\n  .ft-bottom-links{\n    display:flex; gap: 22px;\n    flex-wrap: wrap;\n  }\n  .ft-bottom-links a{\n    color: var(--muted);\n    transition: color .2s;\n  }\n  .ft-bottom-links a:hover{ color: var(--heading); }\n\n  @media (max-width: 1024px){\n    .ft-grid{ grid-template-columns: 1fr 1fr; }\n    .ft-brand{ grid-column: 1 / -1; max-width: 480px; }\n  }\n  @media (max-width: 640px){\n    .ft-grid{ grid-template-columns: 1fr; gap: 36px; }\n    .ft-brand{ grid-column: auto; }\n    .ft-bottom{ flex-direction: column; align-items: flex-start; }\n  }";
